features.snippet:
parameter integer DIM_1 = 17;
parameter integer DIM_2 = 7;
input  wire [DIM_1*DIM_2-1:0] din;
reg [DIM_1-1:0] mem [DIM_2-1:0];
mem[i] = din[DIM_1*i +: DIM_1];

always @* begin
  for (i = 0; i < DIM_2; i=i+1)
    dst_array[i] = src_array[i];
end
always @* begin
  for (i = 0; i < DIM_2; i=i+1)
    dout[DIM_1*i +: DIM_1] = dst_array[i];
end
